parameters.jsCode:
let raw = $input.first().json.output;

// Remove markdown
raw = raw.replace(/```json/g, '').replace(/```/g, '').trim();

try {
  const data = JSON.parse(raw);

  return data.map(item => ({ json: item }));

} catch (e) {
  return [{
  json: {
    error_type: "FORMAT_ERROR",
    message: "Invalid AI JSON format",
    raw_output: raw,
    stage: "parsing"
  }
}];
}
